// ── Sensor Simulator ──
// Initialise persistent state on first run
let s = context.global.get("robot_state");
if (!s) {
    s = {
        vib: 22, temp: 36.2,
        battery: 98, speed: 100, speedLimit: 100,
        robotX: 140, robotY: 95, robotAngle: 0,
        robState: 'running',
        payload: false, riskScore: 0, predAlert: false,
        vibHistory: [], tempHistory: [],
        pathHist: [],
        isPatrolling: false, isDocking: false,
        isSpinning: false, waypointSet: false,
        patrolIndex: 0,
        zone: 'A',
        activeTemplates: [],
        manualDir: null,
        modes: ['smart']
    };
    context.global.set("robot_state", s);
}


// Sensor drift
s.vib  = Math.min(100, Math.max(0, s.vib  + (Math.random() - 0.5) * 5));
s.temp = Math.min(80,  Math.max(20, s.temp + (Math.random() - 0.5) * 1.2));

if (s.robState === 'running') {
    s.battery = Math.max(0, s.battery - Math.random() * 0.18);
}

if (Math.random() < 0.025) s.payload = !s.payload;

s.vibHistory.push(s.vib);
s.tempHistory.push(s.temp);
if (s.vibHistory.length > 120) s.vibHistory.shift();
if (s.tempHistory.length > 120) s.tempHistory.shift();

s.riskScore = Math.min(100, s.vib * 0.6 + Math.max(0, s.temp - 40) * 1.5);

// Predictive alert
if (s.vib > 65 && !s.predAlert) {
    s.predAlert = true;
} else if (s.vib < 48) {
    s.predAlert = false;
}

// Zone calculation
const ZONES = [
    { id:'A', x1:0,   y1:0,   x2:160, y2:100 },
    { id:'B', x1:160, y1:0,   x2:300, y2:100 },
    { id:'C', x1:0,   y1:100, x2:100, y2:200 },
    { id:'D', x1:100, y1:100, x2:300, y2:200 }
];
const DOCK_X = 50, DOCK_Y = 150;
const PATROL_WP = [
    {x:80,y:50},{x:220,y:50},{x:250,y:150},{x:150,y:170},{x:50,y:150},{x:80,y:50}
];

function getZone(x, y) {
    for (const z of ZONES) if (x>=z.x1&&x<z.x2&&y>=z.y1&&y<z.y2) return z.id;
    return 'A';
}
function moveTowards(tx, ty, spd) {
    const dx = tx - s.robotX, dy = ty - s.robotY;
    const dist = Math.sqrt(dx*dx + dy*dy);
    if (dist < 4) return true;
    const sp = Math.min(spd, dist);
    s.robotAngle = Math.atan2(dy, dx);
    s.robotX += dx/dist*sp;
    s.robotY += dy/dist*sp;
    s.pathHist.push({x:s.robotX,y:s.robotY});
    if (s.pathHist.length > 35) s.pathHist.shift();
    return false;
}

// Template effects
if (s.activeTemplates.includes('heat') && s.temp > 55 && s.speed > 60) {
    s.speed = 60;
}
if (s.activeTemplates.includes('batt') && s.battery < 20 && s.robState === 'running' && !s.isDocking) {
    s.isDocking = true;
}
if (s.activeTemplates.includes('vib') && s.vib > 70 && s.speed > 50) {
    s.speed = 50;
}
if (s.activeTemplates.includes('nav') && Math.random() < 0.05) {
    s.robotAngle += (Math.random() - 0.5) * 0.3;
}

// Movement logic
if (s.robState === 'running') {
    if (s.manualDir) {
        const step = (s.speedLimit/100) * 4;
        const dirs = {forward:[0,-step],backward:[0,step],left:[-step,0],right:[step,0]};
        const [dx,dy] = dirs[s.manualDir] || [0,0];
        s.robotX = Math.min(295, Math.max(5, s.robotX + dx));
        s.robotY = Math.min(195, Math.max(5, s.robotY + dy));
        if (dx!==0||dy!==0) s.robotAngle = Math.atan2(dy, dx);
        s.pathHist.push({x:s.robotX,y:s.robotY});
        if (s.pathHist.length > 35) s.pathHist.shift();
    } else if (s.isDocking) {
        const arrived = moveTowards(DOCK_X, DOCK_Y, (s.speedLimit/100)*3);
        if (arrived) {
            s.isDocking = false;
            s.robState = 'idle';
        }
    } else if (s.waypointSet) {
        const arrived = moveTowards(s.waypointX, s.waypointY, (s.speedLimit/100)*3.5);
        if (arrived) s.waypointSet = false;
    } else if (s.isPatrolling) {
        const wp = PATROL_WP[s.patrolIndex % PATROL_WP.length];
        const arrived = moveTowards(wp.x, wp.y, (s.speedLimit/100)*3);
        if (arrived) s.patrolIndex++;
    } else if (s.isSpinning) {
        s.robotAngle += 0.12;
        s.spinTick = (s.spinTick||0) + 1;
        if (s.spinTick >= 53) { s.isSpinning = false; s.spinTick = 0; }
    } else {
        const spd = s.speedLimit/100;
        const dx = (Math.random()-0.5)*5*spd;
        const dy = (Math.random()-0.5)*5*spd;
        s.robotX = Math.min(295, Math.max(5, s.robotX+dx));
        s.robotY = Math.min(195, Math.max(5, s.robotY+dy));
        s.robotAngle = Math.atan2(dy, dx);
        s.pathHist.push({x:s.robotX,y:s.robotY});
        if (s.pathHist.length > 35) s.pathHist.shift();
    }
    s.speed = Math.min(s.speedLimit, s.speed);
    if (s.speed < s.speedLimit && !s.activeTemplates.includes('heat') && !s.activeTemplates.includes('vib')) {
        s.speed = Math.min(s.speedLimit, s.speed + 1);
    }
}

// Zone charging
s.zone = getZone(s.robotX, s.robotY);
if (s.zone === 'C' && s.robState === 'idle') {
    s.battery = Math.min(100, s.battery + 0.3);
}

// Build output
const payload = {
    vib:      +s.vib.toFixed(2),
    temp:     +s.temp.toFixed(2),
    battery:  +s.battery.toFixed(1),
    speed:    s.speed,
    zone:     s.zone,
    state:    s.robState,
    riskScore: +s.riskScore.toFixed(1),
    predAlert: s.predAlert,
    payload:  s.payload,
    robotX:   +s.robotX.toFixed(1),
    robotY:   +s.robotY.toFixed(1),
    robotAngle: +s.robotAngle.toFixed(3),
    isPatrolling: s.isPatrolling,
    isDocking:    s.isDocking,
    isSpinning:   s.isSpinning,
    activeTemplates: s.activeTemplates,
    pathHist: s.pathHist.slice(-10),
    vibHistory: s.vibHistory.slice(-40),
    tempHistory: s.tempHistory.slice(-40)
};
context.global.set("robot_state", s);
msg.payload = payload;
return msg;

const d = msg.payload;

// Build 8 messages for separate outputs
const battMsg = {payload: d.battery};
const tempMsg = {payload: d.temp};
const vibMsg  = {payload: d.vib};
const speedMsg = {payload: d.speed};
const riskMsg  = {payload: d.riskScore};
const stateMsg = {payload: d.state + ' | Zone ' + d.zone};
const alertMsg = {payload: d};
const chartMsg = {payload: d};

return [battMsg, tempMsg, vibMsg, speedMsg, riskMsg, stateMsg, alertMsg, chartMsg];

const d = msg.payload;
const series = ['Vibration','Temperature'];
const vib = d.vibHistory || [];
const tmp = (d.tempHistory || []).map(v => +(v/80*100).toFixed(1));
const len = Math.max(vib.length, tmp.length);

msg.payload = [
  { series: ['Vibration %'], data: [vib.map((v,i)=>({x:i,y:+v.toFixed(1)}))], labels: [''] },
  { series: ['Temp (scaled)'], data: [tmp.map((v,i)=>({x:i,y:v}))], labels: [''] }
];
return msg;

const d = msg.payload;
const alerts = [];
const ts = new Date().toLocaleTimeString();

if (d.temp > 58) alerts.push({ level:'CRITICAL', icon:'🔥', title:'Critical Temperature', detail:`Motor temp ${d.temp.toFixed(1)}°C — shutdown risk`, ts });
else if (d.temp > 45) alerts.push({ level:'WARNING', icon:'🌡️', title:'High Temperature', detail:`Motor temp ${d.temp.toFixed(1)}°C — monitor closely`, ts });

if (d.vib > 70) alerts.push({ level:'CRITICAL', icon:'📳', title:'Critical Vibration', detail:`Vibration ${d.vib.toFixed(1)}% — reduce speed`, ts });
else if (d.vib > 40) alerts.push({ level:'WARNING', icon:'⚡', title:'Elevated Vibration', detail:`Vibration ${d.vib.toFixed(1)}% — above normal`, ts });

if (d.battery < 20) alerts.push({ level:'CRITICAL', icon:'🔋', title:'Critical Battery', detail:`Battery ${d.battery.toFixed(0)}% — return to charger`, ts });
else if (d.battery < 35) alerts.push({ level:'WARNING', icon:'🔋', title:'Low Battery', detail:`Battery ${d.battery.toFixed(0)}% — schedule charging`, ts });

if (d.predAlert) alerts.push({ level:'WARNING', icon:'🔮', title:'Failure Predicted', detail:'Predictive Agent: motor failure risk rising', ts });
if (d.state === 'error') alerts.push({ level:'CRITICAL', icon:'🚨', title:'System Error', detail:'Robot in error state', ts });
if (d.isPatrolling) alerts.push({ level:'INFO', icon:'🔁', title:'Patrol Active', detail:'Executing patrol route', ts });
if (d.isDocking) alerts.push({ level:'INFO', icon:'🔌', title:'Docking', detail:'Navigating to charging station (Zone C)', ts });

// Format for notification
if (alerts.length > 0) {
    const top = alerts[0];
    msg.payload = `${top.icon} [${top.level}] ${top.title}: ${top.detail} @ ${ts}`;
    msg.topic = top.level;
    // Also send full list
    const listHtml = alerts.map(a => `${a.icon} <b>${a.title}</b>: ${a.detail}`).join('<br>');
    const listMsg = { payload: listHtml };
    return [[msg], [listMsg]];
}
msg.payload = '✅ All systems normal — no active alerts';
const listMsg = { payload: '✅ All systems normal' };
return [[msg], [listMsg]];

const cmd = msg.payload;
const s = context.global.get('robot_state') || {
    vib:22, temp:36.2, battery:98, speed:100, speedLimit:100,
    robotX:140, robotY:95, robotAngle:0,
    robState:'running', payload:false, riskScore:0, predAlert:false,
    vibHistory:[], tempHistory:[], pathHist:[],
    isPatrolling:false, isDocking:false, isSpinning:false,
    waypointSet:false, patrolIndex:0, zone:'A',
    activeTemplates:[], manualDir:null, modes:['smart']
};

switch(cmd) {
    case 'start':
        s.robState = 'running';
        s.speed = Math.min(s.speedLimit, 100);
        s.isDocking = false;
        s.isPatrolling = false;
        node.warn('▶ Robot started');
        break;
    case 'stop':
        s.robState = 'idle';
        s.speed = 0;
        s.manualDir = null;
        s.isPatrolling = false;
        s.isDocking = false;
        node.warn('⏹ Robot stopped');
        break;
    case 'estop':
        s.robState = 'error';
        s.speed = 0;
        s.manualDir = null;
        s.isPatrolling = false;
        s.isDocking = false;
        node.error('🛑 EMERGENCY STOP triggered!');
        break;
    case 'manual':
        s.robState = 'running';
        node.warn('🕹️ Manual control activated');
        break;
    case 'reset':
        s.robState = 'running';
        s.speed = 100;
        s.speedLimit = 100;
        s.vib = 22;
        s.temp = 36.2;
        s.predAlert = false;
        s.robotX = 140;
        s.robotY = 95;
        s.robotAngle = 0;
        s.isPatrolling = false;
        s.isDocking = false;
        s.isSpinning = false;
        s.waypointSet = false;
        s.manualDir = null;
        node.warn('🔄 Robot reset to defaults');
        break;
    case 'dock':
        s.robState = 'running';
        s.isDocking = true;
        s.isPatrolling = false;
        node.warn('🔌 Returning to dock (Zone C)');
        break;
    case 'patrol':
        s.robState = 'running';
        s.isPatrolling = !s.isPatrolling;
        s.isDocking = false;
        s.patrolIndex = 0;
        node.warn(s.isPatrolling ? '🔁 Patrol route activated' : '🔁 Patrol cancelled');
        break;
    case 'spin':
        if (!s.isSpinning) { s.isSpinning = true; s.spinTick = 0; }
        node.warn('🌀 360° scan initiated');
        break;
    case 'waypoint':
        s.waypointX = Math.random()*260+20;
        s.waypointY = Math.random()*160+20;
        s.waypointSet = true;
        s.isPatrolling = false;
        s.isDocking = false;
        node.warn(`📍 Waypoint set (${s.waypointX.toFixed(0)},${s.waypointY.toFixed(0)})`);
        break;
    // Direction keys
    case 'fwd':    s.manualDir = 'forward';  break;
    case 'bwd':    s.manualDir = 'backward'; break;
    case 'left':   s.manualDir = 'left';     break;
    case 'right':  s.manualDir = 'right';    break;
    case 'stop_move': s.manualDir = null;    break;
}

context.global.set('robot_state', s);
msg.payload = { cmd, state: s.robState, speed: s.speed };
return msg;

const s = context.global.get('robot_state') || {};
s.speedLimit = parseInt(msg.payload);
s.speed = Math.min(s.speed || 100, s.speedLimit);
context.global.set('robot_state', s);
msg.payload = `Speed limit → ${s.speedLimit}%`;
return msg;

const id = msg.payload;
const s = context.global.get('robot_state') || { activeTemplates: [] };
if (!s.activeTemplates) s.activeTemplates = [];

const idx = s.activeTemplates.indexOf(id);
let status;
if (idx >= 0) {
    s.activeTemplates.splice(idx, 1);
    status = `❌ Template deactivated: ${id}`;
} else {
    s.activeTemplates.push(id);
    status = `✅ Template activated: ${id}`;
}

context.global.set('robot_state', s);
msg.payload = status;
return msg;

// Triggered by sensor tick — evaluates custom flow nodes
const s = context.global.get('robot_state') || {};
const vib = s.vib || 0;
const temp = s.temp || 0;
const logs = [];

// Sensor → Condition → Action chain simulation
if (vib > 40) {
    logs.push({ type:'warn', msg:`⚖ Condition: vib(${vib.toFixed(1)}) > 40 → TRUE` });
    if (s.speed > 20) {
        s.speed = Math.max(20, s.speed - 30);
        context.global.set('robot_state', s);
        logs.push({ type:'success', msg:`🐢 Reduce Speed → ${s.speed}%` });
    }
    logs.push({ type:'error', msg:`🚨 ALERT: High vibration detected!` });
}
if (temp > 50) {
    logs.push({ type:'warn', msg:`⚖ Condition: temp(${temp.toFixed(1)}) > 50 → TRUE` });
    logs.push({ type:'error', msg:`🔥 ALERT: High temperature warning!` });
}

if (logs.length > 0) {
    msg.payload = logs;
    return msg;
}
msg.payload = [{ type:'info', msg:`📊 Sensors nominal — vib:${vib.toFixed(1)}% temp:${temp.toFixed(1)}°C` }];
return msg;

const logs = msg.payload;
const ts = new Date().toLocaleTimeString();
const html = logs.map(l => `<span style="color:${l.type==='error'?'#ff4545':l.type==='warn'?'#ffb020':l.type==='success'?'#00d97e':'#c2c8d8'}">[${ts}] ${l.msg}</span>`).join('<br>');
msg.payload = html;
return msg;

const q = (msg.payload || '').toLowerCase();
if (!q || q.length < 2) return null;

const s = context.global.get('robot_state') || {
    vib:22, temp:36.2, battery:98, speed:100, riskScore:0,
    predAlert:false, zone:'A', activeTemplates:[], robState:'running'
};

const v = s.vib || 0, t = s.temp || 0, b = s.battery || 98;
const risk = s.riskScore || 0, zone = s.zone || 'A';
const tpls = (s.activeTemplates || []).join(', ') || 'none';

const vibState = v>70?'critical':v>55?'elevated':v>35?'moderate':'normal';
const tempState = t>58?'critical':t>48?'elevated':'normal';

let response = '';

if (/vibrat|anomaly|shak|fault|noise/.test(q)) {
    if (vibState==='critical')
        response = `⚠️ Critical vibration at ${v.toFixed(1)}% in Zone ${zone} — ${(v-40).toFixed(0)}% above threshold. Root cause: likely bearing wear or rotor imbalance. Risk: ${risk.toFixed(0)}%. Immediate speed reduction recommended.`;
    else if (vibState==='elevated')
        response = `Vibration elevated at ${v.toFixed(1)}% (Zone ${zone}). Consistent with early-stage mechanical looseness. Flow rule triggers at threshold 40%.`;
    else
        response = `Vibration normal at ${v.toFixed(1)}%. No anomaly detected in Zone ${zone}.`;

} else if (/temp|heat|thermal/.test(q)) {
    if (tempState==='critical')
        response = `🌡️ Motor temp critically high at ${t.toFixed(1)}°C — above 58°C limit. Recommend halting and 15-minute cooling cycle.`;
    else if (tempState==='elevated')
        response = `Temperature elevated at ${t.toFixed(1)}°C. Active templates: ${tpls}.`;
    else
        response = `Temperature nominal at ${t.toFixed(1)}°C. No thermal concerns.`;

} else if (/mainten|schedul|service|inspect/.test(q)) {
    const urgency = risk>70?'IMMEDIATE':risk>40?'WITHIN 48H':'ROUTINE';
    response = `Maintenance priority: ${urgency}. Vib ${v.toFixed(1)}%, temp ${t.toFixed(1)}°C, risk ${risk.toFixed(0)}%. Inspect: drive motor bearings, wheel fasteners, cooling fan.`;

} else if (/forecast|predict|fail|risk/.test(q)) {
    if (risk>70)
        response = `🔮 HIGH RISK (${risk.toFixed(0)}%). Vibration in Zone ${zone} — bearing failure risk in 3–5 cycles. Activate Predictive Maintenance template.`;
    else if (risk>35)
        response = `🔮 MODERATE RISK (${risk.toFixed(0)}%). Proactive speed reduction recommended.`;
    else
        response = `🔮 LOW RISK (${risk.toFixed(0)}%). Est runtime: ~${Math.round(b/0.18/60)} min on current battery.`;

} else if (/status|health|summary/.test(q)) {
    const ov = risk>70?'CRITICAL':risk>40?'DEGRADED':'NOMINAL';
    response = `Status: ${ov}. Zone: ${zone}. Vib: ${v.toFixed(1)}% (${vibState}), Temp: ${t.toFixed(1)}°C, Speed: ${s.speed}%, Battery: ${b.toFixed(0)}%, Risk: ${risk.toFixed(0)}%. Templates: ${tpls}.`;

} else if (/battery|charge|power/.test(q)) {
    const eta = b<20?'CRITICAL — dock now!':b<40?`~${Math.round((b-20)/0.18/60)} min to critical`:`~${Math.round(b/0.18/60)} min remaining`;
    response = `Battery at ${b.toFixed(0)}%. ${eta}. Auto-return template: ${s.activeTemplates.includes('batt')?'ACTIVE':'not active'}.`;

} else {
    response = `Live data — vib: ${v.toFixed(1)}% (${vibState}), temp: ${t.toFixed(1)}°C, speed: ${s.speed}%, risk: ${risk.toFixed(0)}%, Zone ${zone}. Templates: ${tpls}. Try asking about "anomaly", "temperature", "maintenance", "battery", or "forecast".`;
}

msg.payload = `🤖 AI Agent @ ${new Date().toLocaleTimeString()}:\n${response}`;
return msg;

const s = context.global.get('robot_state') || {};
s.vib = 88;
context.global.set('robot_state', s);
msg.payload = '🔴 Fault injected — vibration set to 88%';
node.warn(msg.payload);
return msg;

const s = context.global.get('robot_state') || { vib:22, temp:36.2, riskScore:0, predAlert:false };
const agents = [
    { name:'Sensor Sim',        state: 'active',   status: `Vib:${(s.vib||0).toFixed(0)} Temp:${(s.temp||0).toFixed(0)}` },
    { name:'State Monitor',     state: 'active',   status: `Risk:${(s.riskScore||0).toFixed(0)}%` },
    { name:'Anomaly Detector',  state: (s.vib>55||s.temp>50)?'warning':'idle',  status: (s.vib>55||s.temp>50)?'Detected':'Monitoring' },
    { name:'Predictive Agent',  state: s.predAlert?'warning':'idle',             status: s.predAlert?'Failure predicted':'Standby' },
    { name:'Decision Agent',    state: (s.vib>65)?'warning':'idle',              status: (s.vib>65)?'Executing':'Waiting' },
    { name:'Flow Builder',      state: 'active',   status: 'Ready' }
];

const html = agents.map(a => {
    const color = a.state==='active'?'#00d97e':a.state==='warning'?'#ffb020':'#4a5168';
    return `<span style="color:${color}">⬤ ${a.name}</span> <span style="color:#7e8799">${a.status}</span>`;
}).join('<br>');
msg.payload = html;
return msg;

const d = msg.payload;
const mqttMsg = {
    payload: JSON.stringify({
        vib: d.vib,
        temp: d.temp,
        battery: d.battery,
        speed: d.speed,
        zone: d.zone,
        state: d.state,
        riskScore: d.riskScore,
        predAlert: d.predAlert,
        ts: new Date().toISOString()
    })
};
return mqttMsg;
